'use client';

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import { usePathname } from 'next/navigation';
import { FaStream, FaTimes } from 'react-icons/fa'; // Importing Font Awesome icons

const navLinks = [
  { label: 'Home', href: '/' },
  { label: 'About', href: '/about' },
  { label: 'Service', href: '/ewaste' }, // Renamed from ewaste.html to /ewaste route
  { label: 'Contact', href: '/contact' },
];

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const pathname = usePathname();

  useEffect(() => {
    const handleScroll = () => {
      if (window.scrollY > 100) {
        setScrolled(true);
      } else {
        setScrolled(false);
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);

  return (
    <header className={`header_wrapper fixed top-0 left-0 w-full z-50 transition-all duration-300 ${scrolled ? 'bg-white shadow-md' : 'bg-transparent'}`}>
      <nav className="navbar navbar-expand-lg py-4">
        <div className="container mx-auto flex justify-between items-center px-4">
          <Link href="/" className="navbar-brand flex items-center">
            <div className="brand-content flex items-center">
              <Image
                src="/images/starbuck logo.png" // Path in public directory
                alt="Logo"
                width={158} // Adjust based on original max-height: 158px
                height={158}
                className="img-fluid max-h-[158px] sm:max-h-[50px]"
              />
              <p className="brand-text ml-2 text-[34px] font-semibold"
                 style={{
                   background: 'linear-gradient(190deg, #0e510e, #00FB82, #127749)',
                   WebkitBackgroundClip: 'text',
                   WebkitTextFillColor: 'transparent',
                 }}
              >
                AUSTIC SCRAP
              </p>
            </div>
          </Link>

          {/* Mobile Toggler */}
          <button
            className="navbar-toggler lg:hidden border-0 shadow-none text-text-black-dark text-2xl"
            onClick={() => setIsOpen(!isOpen)}
            aria-label="Toggle navigation"
          >
            {isOpen ? <FaTimes /> : <FaStream />}
          </button>

          {/* Desktop Menu */}
          <div className="hidden lg:flex justify-end" id="navbarNav">
            <ul className="navbar-nav menu-navbar-nav flex space-x-8">
              {navLinks.map((link) => (
                <li key={link.label} className="nav-item">
                  <Link
                    href={link.href}
                    className={`nav-link text-lg font-normal text-text-primary transition-colors duration-300
                      ${pathname === link.href ? 'text-text-secondary' : 'hover:text-text-secondary'}`}
                  >
                    {link.label}
                  </Link>
                </li>
              ))}
            </ul>
          </div>

          {/* Mobile Menu Overlay */}
          <div
            className={`fixed top-0 right-0 h-full w-[60%] bg-bg-light-green p-4 transition-transform duration-300 ease-in-out lg:hidden
            ${isOpen ? 'translate-x-0' : 'translate-x-full'}`}
          >
            <div className="flex justify-end pt-2 pr-2">
              <button
                className="text-color-wheat text-2xl"
                onClick={() => setIsOpen(false)}
                aria-label="Close menu"
              >
                <FaTimes />
              </button>
            </div>
            <ul className="flex flex-col items-center mt-8 space-y-6">
              {navLinks.map((link) => (
                <li key={link.label} className="nav-item">
                  <Link
                    href={link.href}
                    className={`nav-link text-xl text-color-wheat
                      ${pathname === link.href ? 'font-bold' : 'hover:underline'}`}
                    onClick={() => setIsOpen(false)} // Close menu on link click
                  >
                    {link.label}
                  </Link>
                </li>
              ))}
            </ul>
          </div>
        </div>
      </nav>
    </header>
  );
};

export default Navbar;